    notifyListeners();
  }

  Future<bool> refreshTokens() async {
    if (_tokens == null) return false;

    try {
      final newTokens = await _performTokenRefresh(_tokens!.refreshToken);

      _tokens = newTokens;

      await _secureStorage.write(
        key: _tokenKey,
